def validate_nonce(nonce):
    if 'nonce' not in session:
        return False
    return session['nonce'] == nonce

def decode_id_token(id_token):
    # Split the JWT
    header, payload, signature = id_token.split('.')
    
    # Add padding if needed
    payload += '=' * (4 - len(payload) % 4)
    
